  val validHosts = Set("example.com", "partnerapi.com") // Add valid hosts here

  def isValidHost(uri: URI): Boolean = {
    val host = uri.getHost
    validHosts.contains(host) && !isInternalAddress(host)
  }

  def isInternalAddress(host: String): Boolean = {
    val address = InetAddress.getByName(host)
    address.isSiteLocalAddress || address.isLoopbackAddress || address.isAnyLocalAddress
  }

